from flask import Flask, request, session, redirect, url_for, render_template_string
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your_secret_key'

def parse_saml_response(saml_response_xml):
    try:
        root = ET.fromstring(saml_response_xml)
        assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
        if assertion is None:
            raise ValueError("No valid assertion found")
        
        user_attributes = {}
        for attr in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attr.get('Name')
            attr_value = attr.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            user_attributes[attr_name] = attr_value
        
        return user_attributes
    except ET.ParseError as e:
        raise ValueError("Invalid SAML Response XML") from e

@app.route('/saml/acs', methods=['POST'])
def acs():
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        return "Error: No SAML Response", 400
    
    try:
        user_attributes = parse_saml_response(saml_response)
        session['user_attributes'] = user_attributes
        return redirect(url_for('welcome'))
    except Exception as e:
        return str(e), 400

@app.route('/welcome')
def welcome():
    if 'user_attributes' not in session:
        return redirect(url_for('acs'))
    
    user_data = session['user_attributes']
    return render_template_string("<h1>Welcome {{ user_data['Username'] }}</h1>", user_data=user_data)

if __name__ == '__main__':
    app.run(debug=True)